mapper.select:
SELECT B1.* FROM ( SELECT A1.* , ROW_NUMBER() OVER() AS PAGEINDEX FROM ( SELECT req.REQUEST_NO AS requestNo/* 요청번호 */ , req.OBJECT_TYPE AS objectType/* 자료 유형 */ , reqMapping.OBJECT_NM AS objectNm/* 자료명 */ , reqFile.ORG_FILE_NM AS fileNm , ( SELECT COMPANY_NM FROM DOCS_COMPANY company WHERE company.COMPANY_CD = req.DEPLOY_COMPANY_CD ) AS deployCompanyNm , req.DEPLOY_COMPANY_CD AS deployCompanyCd/* 배포업체 */ , CASE WHEN DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = #{sessionLang}) WHEN DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = #{sessionLang}) ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = #{sessionLang}) END AS distributeMethodNm /* 배포방식 */ , CASE WHEN DEPLOY_NORMAL_YN = 'Y' THEN 'NORMAL' WHEN DEPLOY_SPECIAL_YN = 'Y' THEN 'SPECIAL' ELSE 'VIEWING' END AS distributeTypeCd /* 배포유형_CODE */ , req.REQUEST_PURPOSE AS requestPurpose/* 용도 */ , req.INSERT_USER_CD AS requestUserCd/* 요청자 */ , reqUser.USER_NM AS requestUserNm /* 요청자*/ , TO_CHAR(req.INSERT_DT, 'YYYY-MM-DD') AS requestDt/* 요청일 */ , TO_CHAR(TO_DATE(reqFile.USE_END_YMD, 'YYYYMMDD'), 'YYYY-MM-DD') AS useEndYmd/* 유효기간 */ , accUser.USER_CD AS purchaserUserCd , accUser.USER_NM AS purchaserUserNm/* 구매담당자 */ , req.BUSINESS_AREA_CD AS businessAreaCd/* 사업장 */ , reqMapping.OBJECT_ID AS objectId , reqFile.FILE_NO AS fileNo , companyUser.USER_CD AS companyUserCd /* 업체담당자 */ , companyUser.USER_NM AS companyUserNm /* 업체담당자 */ , ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = req.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm /* 배포자 */ , req.VENDOR_ACCEPT_YN AS vendorAcceptYn /* 업체접수여부 */ , FN_GET_CD_NM('vendorAcceptYn', req.VENDOR_ACCEPT_YN, 'ko') AS vendorAcceptNm /* 업체접수여부 */ , req.VENDOR_ACCEPT_USER_CD AS vendorAcceptUserCd /* 업체접수자 */ , (SELECT acceptUser.USER_NM FROM DOCS_USER acceptUser WHERE acceptUser.USER_CD = req.VENDOR_ACCEPT_USER_CD) AS vendorAcceptUserNm /* 업체접수자 */ , TO_CHAR(req.VENDOR_ACCEPT_DT, 'YYYY-MM-DD') AS vendorAcceptDt /* 업체접수일 */ , reqFile.DESTROY_TYPE AS destroyType /* 폐기구분 */ , reqFile.DESTROY_STATUS_CD AS destroyStatusCd , FN_GET_CD_NM('destroyStatusCd', reqFile.DESTROY_STATUS_CD, 'ko') AS destroyStatusNm /* 폐기상태 */ , FN_GET_CD_NM('destroyType', reqFile.DESTROY_TYPE, 'ko') AS destroyTypeNm FROM DOCS_REQUEST req INNER JOIN DOCS_REQUEST_MAPPING reqMapping ON reqMapping.REQUEST_NO = req.REQUEST_NO INNER JOIN DOCS_REQUEST_FILE reqFile ON reqMapping.REQUEST_NO = reqFile.REQUEST_NO AND reqMapping.OBJECT_ID = reqFile.OBJECT_ID INNER JOIN DOCS_REQUEST_DETAIL accDetail ON accDetail.REQUEST_NO = req.REQUEST_NO AND accDetail.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_USER accUser ON accUser.USER_CD = accDetail.ORIGINAL_USER_CD INNER JOIN DOCS_USER reqUser ON reqUser.USER_CD = req.INSERT_USER_CD INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = req.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD WHERE REQUEST_TYPE = 'OUT-REG' AND req.VENDOR_ACCEPT_YN = 'Y' /* 디펜스 자료접수한 대상만 표시 */
AND req.INSERT_DT BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD')+1
ORDER BY requestDt DESC
ORDER BY ${sortColumn} ${order}
) A1 WHERE 1=1
AND requestNo = #{requestNo}
AND deployCompanyCd = #{deployCompanyCd}
AND objectNm LIKE '%' || #{objectNm} || '%'
AND requestUserCd = #{requestUserCd}
AND businessAreaCd = #{businessAreaCd}
AND objectType = #{objectType}
AND destroyStatusCd = #{destroyStatusCd}
AND ROW_NUMBER() OVER() <= #{end}
) B1
WHERE PAGEINDEX >= #{start}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT B1.* FROM ( SELECT A1.* FROM ( SELECT req.REQUEST_NO AS requestNo/* 요청번호 */ , req.OBJECT_TYPE AS objectType/* 자료 유형 */ , reqMapping.OBJECT_NM AS objectNm/* 자료명 */ , reqFile.ORG_FILE_NM AS fileNm , ( SELECT COMPANY_NM FROM DOCS_COMPANY company WHERE company.COMPANY_CD = req.DEPLOY_COMPANY_CD ) AS deployCompanyNm , req.DEPLOY_COMPANY_CD AS deployCompanyCd/* 배포업체 */ , CASE WHEN DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = #{sessionLang}) WHEN DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = #{sessionLang}) ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = #{sessionLang}) END AS distributeMethodNm /* 배포방식 */ , CASE WHEN DEPLOY_NORMAL_YN = 'Y' THEN 'NORMAL' WHEN DEPLOY_SPECIAL_YN = 'Y' THEN 'SPECIAL' ELSE 'VIEWING' END AS distributeTypeCd /* 배포유형_CODE */ , req.REQUEST_PURPOSE AS requestPurpose/* 용도 */ , req.INSERT_USER_CD AS requestUserCd/* 요청자 */ , reqUser.USER_NM AS requestUserNm /* 요청자*/ , TO_CHAR(req.INSERT_DT, 'YYYY-MM-DD') AS requestDt/* 요청일 */ , TO_CHAR(TO_DATE(reqFile.USE_END_YMD, 'YYYYMMDD'), 'YYYY-MM-DD') AS useEndYmd/* 유효기간 */ , accUser.USER_CD AS purchaserUserCd , accUser.USER_NM AS purchaserUserNm/* 구매담당자 */ , req.BUSINESS_AREA_CD AS businessAreaCd/* 사업장 */ , reqMapping.OBJECT_ID AS objectId , reqFile.FILE_NO AS fileNo , companyUser.USER_CD AS companyUserCd /* 업체담당자 */ , companyUser.USER_NM AS companyUserNm /* 업체담당자 */ , ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = req.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm /* 배포자 */ , req.VENDOR_ACCEPT_YN AS vendorAcceptYn /* 업체접수여부 */ , FN_GET_CD_NM('vendorAcceptYn', req.VENDOR_ACCEPT_YN, 'ko') AS vendorAcceptNm /* 업체접수여부 */ , req.VENDOR_ACCEPT_USER_CD AS vendorAcceptUserCd /* 업체접수자 */ , (SELECT acceptUser.USER_NM FROM DOCS_USER acceptUser WHERE acceptUser.USER_CD = req.VENDOR_ACCEPT_USER_CD) AS vendorAcceptUserNm /* 업체접수자 */ , req.VENDOR_ACCEPT_DT AS vendorAcceptDt /* 업체접수일 */ , reqFile.DESTROY_TYPE AS destroyType /* 폐기구분 */ , reqFile.DESTROY_STATUS_CD AS destroyStatusCd , FN_GET_CD_NM('destroyStatusCd', reqFile.DESTROY_STATUS_CD, 'ko') AS destroyStatusNm /* 폐기상태 */ , FN_GET_CD_NM('destroyType', reqFile.DESTROY_TYPE, 'ko') AS destroyTypeNm FROM DOCS_REQUEST req INNER JOIN DOCS_REQUEST_MAPPING reqMapping ON reqMapping.REQUEST_NO = req.REQUEST_NO INNER JOIN DOCS_REQUEST_FILE reqFile ON reqMapping.REQUEST_NO = reqFile.REQUEST_NO AND reqMapping.OBJECT_ID = reqFile.OBJECT_ID INNER JOIN DOCS_REQUEST_DETAIL accDetail ON accDetail.REQUEST_NO = req.REQUEST_NO AND accDetail.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_USER accUser ON accUser.USER_CD = accDetail.ORIGINAL_USER_CD INNER JOIN DOCS_USER reqUser ON reqUser.USER_CD = req.INSERT_USER_CD INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = req.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD WHERE REQUEST_TYPE = 'OUT-REG' AND req.VENDOR_ACCEPT_YN = 'Y' /* 디펜스 자료접수한 대상만 표시 */
AND req.INSERT_DT BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD')+1
ORDER BY requestDt DESC
ORDER BY ${sortColumn} ${order}
) A1 WHERE 1=1
AND requestNo = #{requestNo}
AND deployCompanyCd = #{deployCompanyCd}
AND objectNm LIKE '%' || #{objectNm} || '%'
AND requestUserCd = #{requestUserCd}
AND businessAreaCd = #{businessAreaCd}
AND objectType = #{objectType}
AND destroyStatusCd = #{destroyStatusCd}
) B1 ) C1
